#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N,K,X; scanf("%lld %lld %lld",&N,&K,&X);
        if(X>K){
            printf("-1\n");
            continue;
        }
        long long filler = (X<N)? X+1 : 0; // value different from X and ≤ N
        for(long long i=0;i<N;i++){
            long long pos = i%K;
            long long val = (pos<X)? pos : filler;
            printf("%lld",val);
            if(i+1==N) printf("\n"); else printf(" ");
        }
    }
    return 0;
}

