const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const X = Number(input[idx++]);
  if (X > K) {
    out.push('-1');
    continue;
  }
  const filler = (X < N) ? X + 1 : 0;
  let arr = new Array(N);
  for (let i = 0; i < N; i++) {
    const pos = i % K;
    arr[i] = (pos < X) ? pos : filler;
  }
  out.push(arr.join(' '));
